function updateCaseEventRegisterJudgment() 
{  	
	var caseEventSeq = Services.getValue("/ds/CaseEvent/CaseEventSeq");
	var eventDetails = Services.getValue("/ds/EnterVariableData/Judgment/isregistered");
	var params = new ServiceParams();
	var caseEventDOM = XML.createDOM(null,null,null);
	var judgmentid = Services.getValue( "/ds/EnterVariableData/newjudgmentid");
	var caseNumber = WP.GetScreenProcess().getCaseNumber();
	var owningCourt = WPU.getCaseOwningCourt();
	var eventDate = Services.getValue("/ds/CaseEvent/EventDate");
	var eventId = Services.getValue("/ds/CaseEvent/StandardEventId");
	var subjectNo = Services.getValue("/ds/CaseEvent/SubjectCasePartyNumber");
	
	caseEventDOM.loadXML("<CaseEvent><CaseEventSeq>" + caseEventSeq + "</CaseEventSeq>"+
						"<EventDetails>" + eventDetails + "</EventDetails>"+
						"<JudgmentSeq>"+judgmentid+"</JudgmentSeq>"+
						"<CaseNumber>"+caseNumber+"</CaseNumber>"+
						"<OwningCourt>"+owningCourt+"</OwningCourt>"+
						"<EventDate>"+eventDate+"</EventDate>"+
						"<StdEventId>"+eventId+"</StdEventId>"+
						"<CasePartyNumber>"+subjectNo+"</CasePartyNumber>"+
						"</CaseEvent>");
	
	params.addDOMParameter("caseEvent", caseEventDOM );		
	Services.callService("updateCaseEventRegisterJudgment", params, updateCaseEventRegisterJudgmentCallback, true);	
	Save_All();  
}

	
function updateCaseEventRegisterJudgmentCallback() { }

updateCaseEventRegisterJudgmentCallback.onSuccess = function(dom) {

	if (null != dom) 
	{   				
		
		Save_All();  		
	}
	else {
		alert(Messages.NO_RESULTS_MESSAGE); } }

updateCaseEventRegisterJudgmentCallback.onBusinessException = function(exception)  
{

	alert(Messages.FAILEDSAVE_MESSAGE); 
}

updateCaseEventRegisterJudgmentCallback.onSystemException = function(exception) 
{

	alert(Messages.FAILEDSAVE_MESSAGE); 
}
